#
# Bridge1x2WrTB - Testbench for bridge_1x2_wr
# Generated by bridge test generator from TOML/CSV configuration.
#
# Architecture:
#   - Masters use protocol-specific BFMs (AXI4MasterRead/Write,
#     AXIL4MasterRead/Write, APBMaster). NEVER bare GAXI — reaching past
#     the protocol BFM bypasses the framework's memory model, ID tracking,
#     response generation, and compliance checking, forcing the test to
#     reimplement protocol semantics by hand.
#   - Slaves use protocol-specific BFMs (AXI4SlaveRead/Write,
#     AXIL4SlaveRead/Write, APBSlave), each backed by its own MemoryModel
#     pre-seeded with a distinct per-slave pattern. The slave BFM auto-
#     responds from memory honoring whatever ARSIZE/ARLEN/ARADDR the
#     bridge forwards, so the same TB works across direct, width-converted,
#     and AXIL-shimmed paths.
#
# Slave memory seed pattern (32-bit data path):
#   value(slave_idx, word_offset) = ((slave_idx+1) << 24) | (word_offset & 0xFFFFFF)
#
#   Upper byte = (1-indexed) slave ID, lower 24 bits = word index within
#   the slave's window. A misroute is visible at a glance: a read of
#   slave 4 that returns 0x02_xxxxxx came from slave 1.

import os
import sys

# Import framework utilities (PYTHONPATH includes bin/)
from TBClasses.shared.utilities import get_repo_root

# Add repo root to Python path using robust git-based method
repo_root = get_repo_root()
sys.path.insert(0, repo_root)

import cocotb
from cocotb.triggers import RisingEdge, ClockCycles
from TBClasses.shared.tbbase import TBBase

# Protocol BFMs — required entry points for every transaction.
from CocoTBFramework.components.axi4.axi4_interfaces import (
    AXI4MasterRead, AXI4MasterWrite, AXI4SlaveRead, AXI4SlaveWrite,
)
from CocoTBFramework.components.axil4.axil4_interfaces import (
    AXIL4MasterRead, AXIL4MasterWrite, AXIL4SlaveRead, AXIL4SlaveWrite,
)
from CocoTBFramework.components.apb.apb_components import APBMaster, APBSlave

# Memory model — shared across all protocol slave BFMs (every slave gets
# its own instance, pre-seeded with a distinct pattern).
from CocoTBFramework.components.shared.memory_model import MemoryModel


class Bridge1x2WrTB(TBBase):
    """
    Testbench for bridge_1x2_wr bridge.

    Configuration:
        Masters: 1 (cpu_wr)
        Slaves:  2 (ddr_wr, sram_wr)
        Channels: WR
        Data Width: 32
        Addr Width: 64
        ID Width: 8
    """

    # ----------------------------------------------------------------------
    # Construction
    # ----------------------------------------------------------------------

    def __init__(self, dut):
        super().__init__(dut)
        self.dut = dut
        self.clock = dut.aclk
        self.clock_name = 'aclk'
        self.reset_n = dut.aresetn

        # Bridge configuration
        self.num_masters = 1
        self.num_slaves = 2
        self.data_width = 32
        self.addr_width = 64
        self.id_width = 8

        # Per-slave metadata used by misroute checks and pattern computation.
        # slave_info[i] = (protocol, base_addr, addr_range, data_width)
        self.slave_info = {
            0: ('axi4', 0x00000000, 0x80000000, 32),  # ddr_wr
            1: ('axi4', 0x80000000, 0x80000000, 32),  # sram_wr
        }

        # Per-master data width (in bits). Used by master_read/write helpers
        # and by slave_mem_read so verification reads back master-width
        # bytes regardless of the slave's native width.
        self.master_data_width = {
            0: 32,  # cpu_wr
        }

        # Slave memory models — one per slave, pre-seeded.
        self.slave_memory = {}
        # Slave BFMs (auto-responds from memory_model).
        # For rw slaves we keep both read+write handles.
        self.slave_rd = {}
        self.slave_wr = {}
        # APB doesn't split rd/wr — single APBSlave per port.
        self.slave_apb = {}

        # Passive observation buffers for misroute checks.
        # cocotb_bus.monitors.Monitor._recv suppresses _recvQ.append when
        # callbacks are installed. Since the protocol slave BFMs install
        # their auto-response callback, _recvQ never populates and a
        # naive _recvQ check would see "nothing arrived" even when the
        # bridge did route correctly. We install a *second*, passive
        # callback alongside the BFM's response callback that simply
        # appends each observed packet to these per-slave lists.
        self.observed_ar = {i: [] for i in range(2)}
        self.observed_aw = {i: [] for i in range(2)}

        # Master BFMs — separate read and write handles. For wr-only or
        # rd-only masters only one of these gets populated.
        self.master_rd = {}
        self.master_wr = {}
        # APB master (one handle per APB master port).
        self.master_apb = {}

        self._setup_slave_0_ddr_wr()
        self._setup_slave_1_sram_wr()
        self._setup_master_0_cpu_wr()

    # ----------------------------------------------------------------------
    # Slave seed pattern
    # ----------------------------------------------------------------------

    @staticmethod
    def _seed_value(slave_idx: int, word_offset: int, data_width: int) -> int:
        """Deterministic seed pattern for slave[slave_idx]'s memory.

        Encoding (32-bit case): upper byte = slave_idx+1, lower 24 bits =
        word index. Generalizes to wider data widths by placing the slave
        ID byte in the top byte of the data word (so a hex dump still
        shows the slave ID in the high nibbles).
        """
        id_byte = (slave_idx + 1) & 0xFF
        index_mask = (1 << (data_width - 8)) - 1
        return (id_byte << (data_width - 8)) | (word_offset & index_mask)

    # Cap the per-slave MemoryModel size. The seeded pattern is purely a
    # test fixture — bytes the bridge moves out of memory; the slave's
    # natural addr_range in the TOML can be huge (e.g. 1 GB DDR window)
    # but tests only ever touch a handful of addresses. Eager-filling
    # the full window OOM's the safety monitor (numpy uint8 for data
    # plus two uint32 access-tracking maps = 9 bytes per addressable
    # byte, scaled across multiple multi-hundred-MB slaves).
    #
    # Pre-seed the first SLAVE_MEM_CAP_BYTES of each slave; tests must
    # probe within that window. Misroute-only tests (address_decode end-
    # of-range probes) skip the data assertion past this cap.
    SLAVE_MEM_CAP_BYTES = 4096

    def _build_preset(self, slave_idx: int, addr_range: int, data_width: int) -> bytearray:
        """Build the bytearray preset for a slave's MemoryModel. Caps the
        seeded region at SLAVE_MEM_CAP_BYTES — see the class-level note."""
        bytes_per_word = data_width // 8
        effective = min(addr_range, self.SLAVE_MEM_CAP_BYTES)
        num_words = effective // bytes_per_word
        buf = bytearray(effective)
        for w in range(num_words):
            v = self._seed_value(slave_idx, w, data_width)
            chunk = v.to_bytes(bytes_per_word, 'little')
            buf[w * bytes_per_word:(w + 1) * bytes_per_word] = chunk
        return buf

    def _slave_mem_bytes(self, slave_idx: int) -> int:
        """Return the actual MemoryModel byte capacity for slave_idx
        (= min(addr_range, SLAVE_MEM_CAP_BYTES))."""
        _, _, addr_range, _ = self.slave_info[slave_idx]
        return min(addr_range, self.SLAVE_MEM_CAP_BYTES)

    def expected_pattern(self, slave_idx: int, addr: int) -> int:
        """Return the seeded *master-width* value at the given absolute
        address. Reads `master_data_width_bytes` bytes of memory at
        addr (relative to the slave's base) and interprets little-endian.

        Works for direct paths, width-converted paths, and AXIL-shimmed
        paths uniformly — the bridge moves bytes; we read the same bytes
        back and the master's view is whatever those bytes spell out at
        its data width."""
        # Default to the first master's width — single-master configs
        # this is unambiguous. For multi-master, callers should use
        # slave_mem_read(slave_idx, addr, byte_count=...) explicitly.
        master_width = self.master_data_width.get(0, self.data_width)
        return self.slave_mem_read(slave_idx, addr, byte_count=master_width // 8)

    def slave_mem_read(self, slave_idx: int, addr: int, byte_count: int = None) -> int:
        """Read `byte_count` bytes from slave[slave_idx]'s memory at
        absolute address `addr` and return as a little-endian int.

        If byte_count is None, defaults to master 0's data width in bytes.
        For APB slaves, reads directly from the APBSlave's internal memory."""
        proto, base, _, slave_dw = self.slave_info[slave_idx]
        if byte_count is None:
            master_width = self.master_data_width.get(0, self.data_width)
            byte_count = master_width // 8
        offset = addr - base
        if proto == 'apb':
            apb = self.slave_apb[slave_idx]
            data_bytes = apb.mem.read(offset, byte_count)
        else:
            mem = self.slave_memory[slave_idx]
            data_bytes = mem.read(offset, byte_count)
        return int.from_bytes(bytes(data_bytes), 'little')

    # ----------------------------------------------------------------------
    # Per-master setup (uses dispatched protocol BFM)
    # ----------------------------------------------------------------------

    def _setup_master_0_cpu_wr(self):
        """Set up protocol BFMs for master 0: cpu_wr (protocol: axi4)"""
        self.master_wr[0] = AXI4MasterWrite(
            self.dut, self.clock,
            prefix="cpu_wr_axi_",
            log=self.log,
            data_width=32,
            addr_width=32,
            id_width=4,
            user_width=1,
            multi_sig=True,
        )

    # ----------------------------------------------------------------------
    # Per-slave setup (BFM + pre-seeded MemoryModel)
    # ----------------------------------------------------------------------

    def _setup_slave_0_ddr_wr(self):
        """Set up protocol BFM and pre-seeded MemoryModel for slave 0: ddr_wr (protocol: axi4)"""
        # AXI4 slave — full memory-backed BFM.
        bytes_per_line = 32 // 8
        addr_range = 0x80000000
        # Cap MemoryModel size — see SLAVE_MEM_CAP_BYTES comment.
        mem_bytes = min(addr_range, self.SLAVE_MEM_CAP_BYTES)
        preset = self._build_preset(0, addr_range, 32)
        self.slave_memory[0] = MemoryModel(
            num_lines=mem_bytes // bytes_per_line,
            bytes_per_line=bytes_per_line,
            preset_values=list(preset),
            log=self.log,
        )
        self.slave_wr[0] = AXI4SlaveWrite(
            self.dut, self.clock,
            prefix="ddr_wr_axi_",
            log=self.log,
            data_width=32,
            addr_width=32,
            id_width=4,
            user_width=1,
            multi_sig=True,
            memory_model=self.slave_memory[0],
            base_addr=0x00000000,
        )
        self.slave_wr[0].aw_channel.add_callback(
            lambda pkt, _i=0: self.observed_aw[_i].append(pkt))
    def _setup_slave_1_sram_wr(self):
        """Set up protocol BFM and pre-seeded MemoryModel for slave 1: sram_wr (protocol: axi4)"""
        # AXI4 slave — full memory-backed BFM.
        bytes_per_line = 32 // 8
        addr_range = 0x80000000
        # Cap MemoryModel size — see SLAVE_MEM_CAP_BYTES comment.
        mem_bytes = min(addr_range, self.SLAVE_MEM_CAP_BYTES)
        preset = self._build_preset(1, addr_range, 32)
        self.slave_memory[1] = MemoryModel(
            num_lines=mem_bytes // bytes_per_line,
            bytes_per_line=bytes_per_line,
            preset_values=list(preset),
            log=self.log,
        )
        self.slave_wr[1] = AXI4SlaveWrite(
            self.dut, self.clock,
            prefix="sram_wr_axi_",
            log=self.log,
            data_width=32,
            addr_width=32,
            id_width=4,
            user_width=1,
            multi_sig=True,
            memory_model=self.slave_memory[1],
            base_addr=0x80000000,
        )
        self.slave_wr[1].aw_channel.add_callback(
            lambda pkt, _i=1: self.observed_aw[_i].append(pkt))

    # ----------------------------------------------------------------------
    # Reset / clock plumbing
    # ----------------------------------------------------------------------

    async def setup_clocks_and_reset(self):
        await self.start_clock(self.clock_name, freq=10, units='ns')
        await self.assert_reset()
        await self.wait_clocks(self.clock_name, 10)
        await self.deassert_reset()
        await self.wait_clocks(self.clock_name, 5)

    async def assert_reset(self):
        self.reset_n.value = 0

    async def deassert_reset(self):
        self.reset_n.value = 1

    # ----------------------------------------------------------------------
    # Transaction helpers — thin wrappers over protocol BFMs
    # ----------------------------------------------------------------------

    def _natural_arsize(self, master_idx: int) -> int:
        """AXI4 ARSIZE/AWSIZE encoding for one beat at the master's native
        data width: log2(bytes_per_beat). The bridge's dwidth converters
        rewrite (size,len) on the way to the slave based on the ratio of
        master_dw to slave_dw — that math only works if the master tells
        the truth about its native beat size. The BFM defaults to size=2
        (4 bytes), which silently misrepresents 64b masters and makes the
        converter emit twice the burst length expected."""
        master_dw = self.master_data_width[master_idx]
        bytes_per_beat = master_dw // 8
        return (bytes_per_beat - 1).bit_length()

    async def master_read(self, master_idx: int, address: int) -> int:
        """Single-beat read from master[master_idx]. Returns master-width int."""
        if master_idx in self.master_apb:
            return await self.master_apb[master_idx].read(address)
        rd = self.master_rd[master_idx]
        return await rd.single_read(address, size=self._natural_arsize(master_idx))

    async def master_write(self, master_idx: int, address: int, data: int) -> None:
        """Single-beat write from master[master_idx]. `data` is master-width."""
        if master_idx in self.master_apb:
            await self.master_apb[master_idx].write(address, data)
            return
        wr = self.master_wr[master_idx]
        await wr.single_write(address, data, size=self._natural_arsize(master_idx))

    # ----------------------------------------------------------------------
    # Misroute verification
    # ----------------------------------------------------------------------
    #
    # `cocotb_bus.monitors.Monitor._recv` suppresses `_recvQ.append` when
    # any callback is installed, and the protocol slave BFMs install their
    # auto-response callback. So we can't peek at `ar_channel._recvQ` to
    # see what arrived. Instead we install a second, passive callback on
    # each slave's AR/AW channel at setup time that mirrors observed
    # packets into per-slave `observed_ar` / `observed_aw` lists. Those
    # are what the misroute checks consume.
    #
    # APB slaves bypass GAXISlave entirely, so they don't surface here.

    def _slave_indices_with_obs(self):
        return [i for i, info in self.slave_info.items() if info[0] != 'apb']

    async def _wait_for_obs(self, observed_list, max_cycles=100):
        """Poll up to max_cycles waiting for `observed_list` to be non-empty."""
        for cyc in range(max_cycles):
            if len(observed_list) > 0:
                return cyc
            await ClockCycles(self.clock, 1)
        return max_cycles

    async def expect_aw_at_slave(self, slave_idx: int, expected_addr: int,
                                  max_settle_cycles: int = 100) -> None:
        """Verify the bridge routed an AW to slave_idx and nowhere else.
        No-op for APB slaves (no GAXISlave callback to hook)."""
        proto = self.slave_info[slave_idx][0]
        if proto == 'apb':
            return
        target = self.observed_aw[slave_idx]
        await self._wait_for_obs(target, max_settle_cycles)
        assert len(target) >= 1, (
            f"AW to slave {slave_idx} (addr=0x{expected_addr:08x}) never arrived "
            f"after {max_settle_cycles} cycles — bridge dropped or misrouted")
        pkt = target.pop(0)
        # Width-converted / AXIL-shimmed paths may down-align AWADDR to
        # the slave's natural word boundary.
        slave_dw = self.slave_info[slave_idx][3]
        bytes_per_word = slave_dw // 8
        aligned = expected_addr & ~(bytes_per_word - 1)
        assert int(pkt.addr) in (expected_addr, aligned), (
            f"AW addr mismatch at slave {slave_idx}: "
            f"got 0x{int(pkt.addr):08x}, expected 0x{expected_addr:08x} "
            f"(or aligned 0x{aligned:08x})")

        for other in self._slave_indices_with_obs():
            if other == slave_idx:
                continue
            other_obs = self.observed_aw[other]
            assert len(other_obs) == 0, (
                f"AW for slave {slave_idx} (addr=0x{expected_addr:08x}) "
                f"leaked to slave {other} (observed={len(other_obs)})")

    async def expect_ar_at_slave(self, slave_idx: int, expected_addr: int,
                                  max_settle_cycles: int = 100) -> None:
        """Read-side analogue of expect_aw_at_slave."""
        proto = self.slave_info[slave_idx][0]
        if proto == 'apb':
            return
        target = self.observed_ar[slave_idx]
        await self._wait_for_obs(target, max_settle_cycles)
        assert len(target) >= 1, (
            f"AR to slave {slave_idx} (addr=0x{expected_addr:08x}) never arrived "
            f"after {max_settle_cycles} cycles")
        pkt = target.pop(0)
        slave_dw = self.slave_info[slave_idx][3]
        bytes_per_word = slave_dw // 8
        aligned = expected_addr & ~(bytes_per_word - 1)
        assert int(pkt.addr) in (expected_addr, aligned), (
            f"AR addr mismatch at slave {slave_idx}: "
            f"got 0x{int(pkt.addr):08x}, expected 0x{expected_addr:08x} "
            f"(or aligned 0x{aligned:08x})")

        for other in self._slave_indices_with_obs():
            if other == slave_idx:
                continue
            other_obs = self.observed_ar[other]
            assert len(other_obs) == 0, (
                f"AR for slave {slave_idx} leaked to slave {other} "
                f"(observed={len(other_obs)})")